importCpg("%s")
import java.util.regex.Pattern

def clean(value: String): String = value.replaceAll("\\s+", " ").take(360)
def lower(value: String): String = clean(value).toLowerCase
def lineNo(c: io.shiftleft.codepropertygraph.generated.nodes.Call): Int = c.lineNumber.getOrElse(0)
def fileName(c: io.shiftleft.codepropertygraph.generated.nodes.Call): String = c.file.name.headOption.getOrElse("unknown")
def baseIdentifier(value: String): String = "[A-Za-z_][A-Za-z0-9_]*".r.findFirstIn(value.replaceAll("[\\*&()\\s]", "")).getOrElse("")
def mentionsIdentifier(code: String, id: String): Boolean = id.nonEmpty && Pattern.compile("\\b" + Pattern.quote(id) + "\\b").matcher(code).find
def isFreeLike(c: io.shiftleft.codepropertygraph.generated.nodes.Call): Boolean = lower(c.code).matches(".*\\b(free|kfree|vfree|kvfree|av_free|av_freep|g_free)\\s*\\(.*") || lower(c.code).contains("delete ")
def isResetOrReassign(c: io.shiftleft.codepropertygraph.generated.nodes.Call, id: String): Boolean = {
  val code = lower(c.code)
  mentionsIdentifier(code, id) && code.contains("=") && (code.contains("null") || code.contains("nullptr") || code.matches(".*=\\s*0\\b.*") || code.contains("malloc") || code.contains("alloc") || code.contains("&"))
}
def isUseAfterFree(c: io.shiftleft.codepropertygraph.generated.nodes.Call, id: String): Boolean = {
  val code = lower(c.code)
  mentionsIdentifier(code, id) && !isFreeLike(c) && (code.contains(id.toLowerCase + "->") || code.contains("*" + id.toLowerCase) || code.contains("* " + id.toLowerCase) || code.contains(id.toLowerCase + "[") || c.argument.code.exists(arg => mentionsIdentifier(lower(arg), id)))
}

cpg.method.foreach { m =>
  val calls = m.call.l.sortBy(lineNo)
  calls.filter(isFreeLike).foreach { freeCall =>
    val ptr = baseIdentifier(freeCall.argument(1).code.headOption.getOrElse(""))
    val freeLine = lineNo(freeCall)
    if (ptr.nonEmpty && freeLine > 0) {
      calls.filter(c => lineNo(c) > freeLine && isUseAfterFree(c, ptr)).take(2).foreach { useCall =>
        val useLine = lineNo(useCall)
        val resetBetween = calls.exists(c => lineNo(c) > freeLine && lineNo(c) < useLine && isResetOrReassign(c, ptr))
        if (!resetBetween) {
          val evidence = clean(s"${ptr} freed at line ${freeLine} and used at line ${useLine}: ${useCall.code}")
          println(s"BNF\t${fileName(useCall)}\t${useLine}\t${ptr}\t${evidence}\tuse-after-free")
        }
      }
    }
  }
}

