importCpg("%s")
import java.util.regex.Pattern

def clean(value: String): String = value.replaceAll("\\s+", " ").take(360)
def lower(value: String): String = clean(value).toLowerCase
def lineNo(c: io.shiftleft.codepropertygraph.generated.nodes.Call): Int = c.lineNumber.getOrElse(0)
def fileName(c: io.shiftleft.codepropertygraph.generated.nodes.Call): String = c.file.name.headOption.getOrElse("unknown")
def assignedIdentifier(code: String): String = {
  val lhs = code.split("=", 2).headOption.getOrElse("")
  "[A-Za-z_][A-Za-z0-9_]*".r.findAllIn(lhs).toList.lastOption.getOrElse("")
}
def mentionsIdentifier(code: String, id: String): Boolean = id.nonEmpty && Pattern.compile("\\b" + Pattern.quote(id) + "\\b").matcher(code).find
def isNullAssignment(c: io.shiftleft.codepropertygraph.generated.nodes.Call): Boolean = {
  val code = lower(c.code)
  code.contains("=") && (code.contains("null") || code.contains("nullptr") || code.matches(".*=\\s*0\\b.*"))
}
def hasNonNullGuard(c: io.shiftleft.codepropertygraph.generated.nodes.Call, id: String): Boolean = c.controlledBy.code.exists { guard =>
  val g = lower(guard)
  mentionsIdentifier(g, id) && (g.contains("!= null") || g.contains("!= nullptr") || g.contains("!= 0") || g.matches(".*\\bif\\s*\\(\\s*" + Pattern.quote(id.toLowerCase) + "\\s*\\).*"))
}
def isReassignedNonNull(c: io.shiftleft.codepropertygraph.generated.nodes.Call, id: String): Boolean = {
  val code = lower(c.code)
  mentionsIdentifier(code, id) && code.contains("=") && !isNullAssignment(c)
}
def isDereference(c: io.shiftleft.codepropertygraph.generated.nodes.Call, id: String): Boolean = {
  val code = lower(c.code)
  mentionsIdentifier(code, id) && (code.contains(id.toLowerCase + "->") || code.contains("*" + id.toLowerCase) || code.contains("* " + id.toLowerCase) || code.contains(id.toLowerCase + "["))
}

cpg.method.foreach { m =>
  val calls = m.call.l.sortBy(lineNo)
  calls.filter(isNullAssignment).foreach { assign =>
    val ptr = assignedIdentifier(assign.code)
    val assignLine = lineNo(assign)
    if (ptr.nonEmpty && assignLine > 0) {
      calls.filter(c => lineNo(c) > assignLine && isDereference(c, ptr) && !hasNonNullGuard(c, ptr)).take(2).foreach { deref =>
        val derefLine = lineNo(deref)
        val reassigned = calls.exists(c => lineNo(c) > assignLine && lineNo(c) < derefLine && isReassignedNonNull(c, ptr))
        if (!reassigned) {
          val evidence = clean(s"${ptr} assigned NULL at line ${assignLine} and dereferenced at line ${derefLine}: ${deref.code}")
          println(s"BNF\t${fileName(deref)}\t${derefLine}\t${ptr}\t${evidence}\tnull-pointer-dereference")
        }
      }
    }
  }
}
